*  or portions thereof marked with this legend must also reproduce the markings. */
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// 2.8 | 2022-05-05 | raj  | STRY0119569 - As a Tasker User, I want to be able to select different form views on New Task Form.
//											New widget built to handle creating new tasks based on task type
// 2.8    | 2022-06-21 - raj -  STRY0116257 - System Setting- Options for limiting available views and setting default "Task Form view" for New Task Forms
//											Updates in Server and HTML
//
//------------------------------------------------------------------------------------------------------------------------
(function($sp, input, data, options, gs) {
  /* populate the 'data' object */
  /* e.g., data.table = $sp.getValue('table'); */
	var taskerFormPreferences;
	data.messages = [];
	data.settings = {};
	data.advancedTaskerTypes = [];
	data.taskerTypes = [];
	// STRY0116257
	data.showAdvancedViews = false;
	data.showQuickViews = false;

	main();
	function main(){
		taskerFormPreferences = new tasker_User_Form_Preferences();
		// if messages not loaded, load messages
		var taskWidgetIconsAndMessage = new TaskerWidgetIconsAndMessages('new_tasker_selection');

		// save form view preference
		if(input){
			if (input.getURL==true){
				var oUserPref = new x_153465_discovert.tasker_User_Form_Preferences();
				var url_Properties = {};
				// if just getting the URL, then get URL and return
				url_Properties = oUserPref.get_URL_Properties_for_Task_Based_on_Prefrences(input.sys_id,input.view);
				data.sys_id = input.sys_id;
				data.pageId = url_Properties.pageId;
				data.pageTable = url_Properties.pageTable;
				data.view = url_Properties.view;
				data.portal_url_ref = url_Properties.portal_url_ref;
				data.isValid = false;
				data.loadingIndicator = true;
				// only call once
				data.getURL = false;
				return;
			}				

			if(input.defaultTaskFormViewUpdated){
				taskWidgetIconsAndMessage.savePreferenceDefaultTaskFormView(input.settings.defaultTaskFormView.sys_id);
			}
			if(input.sys_id){
				data.sys_id = input.sys_id;
			}
		} else {
			data.sys_id = -1;
		}

		// load messages
		data.messages = taskWidgetIconsAndMessage.loadMessages();
		// load settings
		data.settings = taskWidgetIconsAndMessage.loadDefaultsAndSettings($sp);

		data.advancedTaskerTypes = taskerFormPreferences.loadFormViews("advanced_view");
		data.taskerTypes = taskerFormPreferences.loadFormViews("quick_view");
		// STRY0116257
		data.showAdvancedViews = data.advancedTaskerTypes.length>0;
		data.showQuickViews = data.taskerTypes.length>0;

		// NOTE: currently the default is saved as a name, but should be saved as object
		data.selected_id = data.settings.defaultTaskFormView.sys_id;

		data.bifold = (input || {}).bifold || (options || {}).bifold || false;		
		data.isModal = (input || {}).isModal || (options || {}).isModal || false;
		// if the task has been saved, then show the header and icons
		if(data.sys_id != -1){
			data.omit_icons = false;
			data.omitHeader = false;
		} else {
			data.omit_icons = (input || {}).omit_icons || (options || {}).omit_icons || false;
			data.omitHeader = (input || {}).omitHeader || (options || {}).omitHeader || false;
		}
		data.omitHeaderOptions = (input || {}).omitHeaderOptions || (options || {}).omitHeaderOptions || false;

		data.query  = (input || {}).query || (options || {}).query || "";
		_convertToBool(['isModal', 'omit_icons']);
		_loadFormWidget();
	}

	function _loadFormWidget(){
		if(data.settings.defaultTaskFormView){
			// reset load query each time
			var loadQuery = data.query + data.settings.defaultTaskFormView.filter;
			// set loadID above when not advanced, then set query if an ID is set so advanced gets last selected quick type
			data.selected_id = data.settings.defaultTaskFormView.sys_id;
			var form_widget_parameters = {
				table: 'x_153465_discovert_route_task_instance',
				sys_id: data.sys_id,
				sys_id_required: false,
				// NOTE: load based on getting user last selection
				view: data.settings.defaultTaskFormView.sn_view,
				omitHeader: data.omitHeader,
				omitHeaderOptions: data.omitHeaderOptions,
				query:  loadQuery,
				bifold:data.bifold,
				isModal:data.isModal,
				baseWidget: "new_tasker_selection",
				shared: {}
			}
			data.new_task_widget_forms = [];
			var new_task_widget_form = {};
			new_task_widget_form.widget = $sp.getWidget('discovertasker-formtab', form_widget_parameters);
			data.new_task_widget_forms.push(new_task_widget_form);
		}
	}	
	function _convertToBool(names) {
		names.forEach(function(name) {
			data[name] = data[name] == true || data[name] == 'true';
		});
	}
})($sp, input, data, options, gs);
